"""
MKT Context Commentary — Mark chapters 15–16
Run: python3 scripts/zc-context-mark-15-16.py

Source data used:
- data/interlinear/mark.json
- data/translation/draft/mediating/mark.json (MKT text)

Key decisions in this range:
- Mark 15:28 absent from best manuscripts (Sinaiticus, Vaticanus); brief note provided
- Mark 16:9-20 (Long Ending) absent from Sinaiticus and Vaticanus; second-century addition
- The original ending at 16:8 ("they were afraid") is the authentic Markan text
- Centurion's confession (15:39) "Son of God" — ambiguity between Roman imperial title and
  theological title is intentional; narrative parallels God's declarations at baptism and transfig.
- Simon of Cyrene "father of Alexander and Rufus" — specific naming implies known figures in
  Mark's community; possibly identical to Rufus of Rom 16:13
- Darkness at noon (15:33) — echoes Amos 8:9 eschatological sign
- Temple curtain torn "from top to bottom" (15:38) — top-down signals divine action
- Eloi/Elijah confusion (15:34-35) — plausible phonetic mishearing; Ps 22:1 citation activates
  the whole Psalm including its vindication ending (vv.22-31)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK = {
  "15": {
    "2": '<p>"Are you the king of the Jews?" (<em>Su ei ho basileus tōn Ioudaiōn</em>) — Pilate\'s opening question frames the charge as a Roman political one: claiming kingship in the provinces was a capital crime under the <em>lex maiestatis</em> (treason law). Rome permitted client rulers and ethnarchs, but unauthorized self-proclamation as king was tantamount to rebellion. Jesus\'s reply <em>su legeis</em> ("you say [it]" / "you have said so") is a well-attested Hellenistic legal evasion — neither a direct affirmation (which would confirm the charge) nor a denial (which would be false). It throws the claim back on the questioner without conceding or denying the title.</p>',
    "3": '<p>"The chief priests accused him of many things" — Mark does not specify the content of the accusations before Pilate, unlike Luke (23:2-5) which lists: "We have found this man subverting our nation, opposing payment of taxes to Caesar, and claiming to be Messiah, a king." The Roman charges needed to be secular-political (not theological), hence the shift from the Sanhedrin\'s charge of blasphemy (14:64) to charges framed in terms of Roman jurisdiction: sedition, tax evasion, claiming royal title. The Sanhedrin could not execute; only the Roman governor held the <em>ius gladii</em> (right of the sword).</p>',
    "4": '<p>Pilate\'s question "Aren\'t you going to answer? See how many things they are accusing you of" reflects both genuine puzzlement and perhaps tactical concern: Roman legal procedure (<em>cognitio extra ordinem</em>) gave the accused the right to respond, and an accused who simply stood silent was unusual. In the Roman legal tradition, silence could be taken as admission, but it could also be a form of dignified defiance. Pilate\'s question invites Jesus to defend himself within the Roman system — the defense Jesus declines to make.</p>',
    "5": '<p>"But Jesus still made no reply, and Pilate was amazed" (<em>hōste thaumazein ton Pilaton</em>) — the word <em>thaumazein</em> (amazed, marveled) is used elsewhere in Mark for reactions to miracles (5:20, 6:6) and to Jesus\'s authority (12:17). Pilate\'s amazement marks Jesus\'s silence as something outside his ordinary experience of the accused. The silence echoes Isaiah 53:7 ("He was oppressed and afflicted, yet he did not open his mouth; he was led like a lamb to the slaughter, and as a sheep before its shearers is silent, so he did not open his mouth") — the Servant\'s silence before his accusers as a defining mark of his mission.</p>',
    "6": '<p>The Passover prisoner release (<em>apolyein</em>) is attested in Mark, Matthew, Luke, and John as a recognized custom (<em>kata de heortēn</em>, "at the festival"). Its historical basis is debated: Josephus and Philo do not mention it, and no Roman documentary parallel survives. However, Roman governors did exercise clemency (<em>indulgentia</em>) at major festivals as a practical tool for maintaining peace. The custom may have been an informal Judean practice that Pilate accommodated. The narrative function is clear: the contrast between the released murderous insurrectionist (Barabbas) and the condemned innocent (Jesus) is theologically central.</p>',
    "7": '<p>Barabbas (<em>Bar-Abbas</em> in Aramaic — "son of the father") was imprisoned for murder committed in "the uprising" (<em>en tē stasei</em>) — the definite article suggests a specific known insurrection in Jerusalem. The same vocabulary (<em>lēstas</em>, insurrectionist/brigand) is used for those crucified with Jesus (v.27). Barabbas was the type of leader many expected the Messiah to be: a violent, insurrectionist "son of the father" overthrowing Roman rule. The exchange — Barabbas released, Jesus crucified — dramatizes the displacement of a violent messianic hope by the actual Messiah who saves by suffering rather than by force.</p>',
    "8": '<p>The crowd "came up" (<em>anabas</em> — going up, perhaps to the elevated platform from which Pilate administered judgment) to request the customary release. The crowd here is not explicitly the same crowd as the Passover pilgrims or the populace that welcomed Jesus on Palm Sunday; it may be a smaller group associated with Barabbas\'s supporters or those who had gathered for the festival. The chief priests will actively work to redirect this crowd\'s request (v.11). Pilate\'s initial offer of Jesus (v.9) assumes the crowd will request him, suggesting he believed popular sentiment favored Jesus.</p>',
    "9": '<p>"Do you want me to release to you the king of the Jews?" — Pilate uses the title sarcastically or as a negotiating move: he knows Jesus has been handed over "out of self-interest" (v.10) and is probing whether popular support for Jesus will override the priests\' agenda. The title "king of the Jews" is the Roman political charge — not "Messiah" or "Son of God" (Jewish theological categories) but the charge as Pilate received it. By using it here, Pilate is simultaneously testing the crowd and signaling that he regards the charge as the priests\' problem, not a real threat to Roman order.</p>',
    "10": '<p>"Knowing it was out of self-interest that the chief priests had handed Jesus over to him" — the word <em>phthonon</em> (self-interest, envy, jealousy) is the political motive Mark ascribes to the chief priests. <em>Phthonos</em> in the ancient world was specifically the envy of those who possess status toward those who threaten to displace them — a recognized and morally condemned vice in both Greek moral philosophy and Jewish wisdom tradition. The Sanhedrin\'s motive is not theological outrage (blasphemy, as they claimed at the trial) but political self-preservation and rivalry. Pilate sees through it.</p>',
    "11": '<p>"But the chief priests stirred up the crowd to have Pilate release Barabbas instead" — the verb <em>anaseisan</em> (stirred up, agitated) is used of crowds being manipulated by demagogy. The reversal of Pilate\'s expectations — the crowd asking for Barabbas rather than Jesus — requires active persuasion from the priests. This detail explains the apparent speed of the shift in popular sentiment between Palm Sunday and Good Friday: it is not the same crowd in the same mood but a crowd being actively worked by the religious establishment with a specific goal in mind.</p>',
    "12": '<p>Pilate\'s second question — "What shall I do, then, with the one you call the king of the Jews?" — is a trap for his own authority: by asking the crowd what to do with a prisoner, he is abdicating the judicial role and transferring the decision to the mob. Roman trial procedure was not supposed to work this way (<em>cognitio</em> was the governor\'s exclusive prerogative), but Pilate is engaged in a political calculation: if the crowd calls for crucifixion, he can comply without personally owning the decision. The crowd will bear responsibility for a verdict that Pilate executes.</p>',
    "13": '<p>"Crucify him!" (<em>Staurōson auton</em>) — crucifixion was the Roman penalty reserved for slaves, non-citizens, and rebels; it was designed to be maximally degrading and maximally visible as a deterrent. Cicero called it "the most cruel and disgusting penalty" (<em>De Verr.</em> 2.5.165). The Jewish crowd crying for crucifixion (a Roman execution method, not a Jewish one) underlines the depths of the chief priests\' operation: they are seeking not just Jesus\'s death but death in the most shameful possible form, publicly discrediting him as a messianic pretender.</p>',
    "14": '<p>"Why? What crime has he committed?" (<em>Ti gar epoiēsen kakon</em>) — Pilate\'s third protest. He has already recognized the self-serving motive of the priests (v.10), offered to release Jesus (v.9), and now asks explicitly for a charge. In all four Gospels, Pilate repeatedly declares Jesus innocent or expresses reluctance (Luke 23:4,14,22; John 18:38; 19:4,6). The mob\'s response — "all the louder, Crucify him!" — replaces legal argument with volume. The trial ends not with evidence of guilt but with a crowd that drowns out every attempt at orderly process.</p>',
    "15": '<p>Flogging (<em>phragellōsas</em> — Latin loanword <em>flagellare</em>) before crucifixion was standard Roman procedure (<em>verberatio</em>). The Roman scourge (<em>flagellum</em>) had leather thongs weighted with metal pieces or bone; it shredded skin and flesh. Unlike the Jewish "forty lashes minus one" (Deut 25:3; 2 Cor 11:24), Roman scourging had no legal limit and was often severe enough to cause the victim to go into shock. "Wanting to satisfy the crowd" (<em>to hikanon poiēsai</em> — "to do the sufficient thing") is a Latinism (<em>satisfacere</em>), confirming Mark\'s Roman context: Pilate does what is politically sufficient to satisfy the crowd, not what justice requires.</p>',
    "16": '<p>The Praetorium (<em>aulē</em>, which Mark glosses as "Praetorium") was the official residence/headquarters of the Roman governor. During major festivals the governor relocated from Caesarea Maritima to Jerusalem; the Praetorium there was either Herod\'s palace (on the western hill) or the Antonia Fortress (adjacent to the temple). The "whole company of soldiers" (<em>holēn tēn speiran</em> — a <em>speira</em> was a cohort of approximately 480-600 soldiers) — the full complement assembled for a mock enthronement ceremony. The scale of the mockery (the entire cohort gathered) makes it a structured parody of a Roman imperial acclamation.</p>',
    "17": '<p>The purple robe (<em>porphyran</em>) was the color of imperial and royal authority in the Roman world — purple dye from murex shellfish was extraordinarily expensive and production was controlled; wearing purple was a privilege of royalty and later senators. The crown of thorns parodies the <em>corona</em> worn by Roman generals and victors (the <em>corona triumphalis</em> of laurel). The "crown" would have been woven from a thorny shrub available locally (Poterium spinosum, Christ\'s thorn, or similar). Together — purple robe, thorns, staff (v.19) as scepter — the soldiers are staging a mock enthronement, a parody of the <em>adventus</em> ceremony for a Roman emperor.</p>',
    "18": '<p>"Hail, king of the Jews!" (<em>Chaire, basileu tōn Ioudaiōn</em>) — a parody of the Roman imperial acclamation "Ave Caesar, Imperator!" The verb <em>chairein</em> (to rejoice, hail) was the standard Greek greeting but also the formula of formal homage. The soldiers are staging a grotesque inversion of an imperial triumph: the conquered king is enthroned in mockery rather than the Roman general acclaimed after victory. The irony Mark expects his Roman readers to catch is that the one being mocked as "king" is the one whose kingship will ultimately be vindicated — and whose kingdom will outlast the Empire that mocks him.</p>',
    "19": '<p>They struck him on the head with a staff (beating down the crown of thorns), spit on him (the gesture of contempt familiar from Isaiah 50:6: "I offered my back to those who beat me... I did not hide my face from mocking and spitting"), and "falling on their knees, paid homage" (<em>gonypetountes prosekynoun</em>) — the kneeling was mock worship, the same gesture used for genuine royal or divine homage. The sequence of actions (crown, robe, acclamation, striking, spitting, kneeling) follows the script of royal enthronement ceremony step by step, making each step a mockery of what it enacts.</p>',
    "20": '<p>"When they had mocked him, they took off the purple robe and put his own clothes on him" — the reversal: the mock regalia removed, his own clothing restored. Crucifixion was carried out in the condemned\'s own garments (which would then be divided among the executioners, v.24). "They led him out to crucify him" — the procession to the place of execution, which condemned men walked themselves (carrying the horizontal beam, the <em>patibulum</em>) unless, as in Jesus\'s case, someone else was pressed into service (v.21). The public procession served the Roman deterrent purpose: visible suffering as a warning to observers.</p>',
    "21": '<p>Simon of Cyrene (<em>Kyrēnaion</em>) was a Jew from Cyrene (modern Libya), which had a large and well-established Jewish community (Acts 2:10 lists Cyrenians among the Diaspora; Acts 6:9 mentions a "Synagogue of the Cyrenians" in Jerusalem). He was "passing by on his way in from the country" (<em>ap\' agrou</em>) — possibly coming in from work in the fields. The Romans exercised <em>angareia</em> (forced service), the legal right to compel civilians to carry burdens; Simon was drafted involuntarily. "The father of Alexander and Rufus" — the specific naming (unique in the Passion Narratives) implies these men were known to Mark\'s community; Rufus appears in Romans 16:13 ("Rufus, chosen in the Lord"), possibly the same person.</p>',
    "22": '<p>Golgotha (<em>Golgotha</em>) is the Greek transliteration of the Aramaic <em>gulgoltha</em> (skull), which Mark translates for his Gentile audience (cf. the Aramaic preservation pattern throughout Mark). Latin: Calvaria (Calvary). The site was outside the city walls (Heb 13:12; Lev 24:14 required execution outside the camp). The traditional location under the Church of the Holy Sepulchre was identified by Helena in the fourth century; the site was a former quarry with rock-cut tombs nearby (consistent with v.46), used as a garden before Jerusalem\'s expansion brought the city walls outward.</p>',
    "23": '<p>"They offered him wine mixed with myrrh, but he did not take it" — the Mishnah (m. Sanhedrin 43a) records that "the women of Jerusalem used to donate [wine and frankincense] and bring it [to condemned men]," apparently as a practice of mercy to dull pain. Wine mixed with myrrh (<em>esmyrnismenon oinon</em>) would function as a mild anesthetic. Jesus\'s refusal is not masochism but intentionality: to remain fully conscious through the Passion, to drink the cup he had prayed over in Gethsemane (14:36) without dilution. The refusal of anesthesia is a deliberate choice to undergo the suffering without numbing.</p>',
    "24": '<p>"They crucified him. Dividing up his clothes, they cast lots to see what each would get" — crucifixion executioners had the right to the condemned\'s possessions as compensation (Roman law, confirmed in Digesta 48.20.6). The division of garments by lot activates Psalm 22:18 ("They divide my clothes among them and cast lots for my garment") without explicit citation — Mark allows the parallel to surface for those who know the Psalm. In the Passion Narrative, multiple Psalm 22 resonances accumulate: the mockers (22:7), the lots for garments (22:18), the cry of dereliction (22:1), creating a sustained intertextual reading of the crucifixion through the lens of the Psalm.</p>',
    "25": '<p>"It was nine in the morning when they crucified him" — the third hour in Jewish time-reckoning (hours counted from sunrise at approximately 6 AM, making the third hour approximately 9 AM). This conflicts with John 19:14, which places Pilate\'s handover of Jesus "about the sixth hour" (approximately noon) — a well-known chronological discrepancy between the Gospels. Several harmonizations have been proposed (different time systems, scribal errors), none fully satisfying. Mark\'s third-hour statement is consistent with his passion chronology and reflects either actual time or a liturgically schematized three-hour period structure (3rd, 6th, 9th hours marking the crucifixion, darkness, and death).</p>',
    "26": '<p>The <em>titulus</em> (inscription of the charge) was a standard Roman practice in crucifixion: the crime for which a person was being executed was written on a wooden tablet (<em>tabella</em>) that preceded the condemned through the streets and was then affixed to the cross. The charge posted above Jesus — "THE KING OF THE JEWS" (<em>ho basileus tōn Ioudaiōn</em>) — represents Pilate\'s final word in the contest with the chief priests (John 19:19-22 records their objection: "Do not write \'The King of the Jews\', but that this man claimed to be king of the Jews." Pilate\'s reply: "What I have written, I have written"). The titulus is both the crime for which Jesus is executed and, Mark\'s narrative implies, the truth Pilate inadvertently proclaims.</p>',
    "27": '<p>Two rebels (<em>lēstas</em>) crucified with Jesus — the same word used for Barabbas\'s associates (v.7) and for those described as "bandits" in the temple controversy (11:17, citing Jer 7:11). <em>Lēstēs</em> covered a range from common criminals to political insurrectionists; Josephus uses it for Jewish resistance fighters against Rome. The placement "one on his right and one on his left" echoes the request of James and John (10:37: "Let one of us sit at your right and the other at your left in your glory"). The two executed rebels occupy the positions of honor in Jesus\'s "kingdom" — though not the way any of the disciples anticipated.</p>',
    "28": '<p>Mark 15:28 ("And the scripture was fulfilled that says, \'He was counted with the transgressors\'") is absent from the oldest and most important manuscripts (Codex Sinaiticus, Codex Vaticanus, and a number of other early witnesses) and is widely recognized as a scribal interpolation from Luke 22:37 (itself citing Isa 53:12). The verse does not appear in Mark\'s original text; it was added by copyists who recognized the Isaiah-53 connection and made it explicit. The connection between the two rebels flanking Jesus and Isaiah 53:12 ("he was numbered with the transgressors") is real but implicit in Mark\'s original.</p>',
    "29": '<p>"Those who passed by hurled insults at him, shaking their heads" — the head-shaking gesture of derision (<em>kephalas kinountes</em>) appears in Psalm 22:7 ("All who see me mock me; they hurl insults, shaking their heads") and Lamentations 2:15. The taunt "So! You who are going to destroy the temple and build it in three days" — this claim is what the false witnesses had alleged at the trial (14:58), and Jesus\'s explanation of it (John 2:19-21: the temple he spoke of was his body) is precisely what will be realized in three days by the resurrection. The mockers taunt with the truth they do not recognize.</p>',
    "30": '<p>"Come down from the cross and save yourself!" — the taunt assumes that saving oneself is incompatible with dying. The irony runs through the entire crucifixion scene: "He saved others but cannot save himself" (v.31); "Let this Messiah, this king of Israel, come down now from the cross, that we may see and believe" (v.32). In each case, the mockers set a condition for belief that, if Jesus met it, would falsify the gospel: a Messiah who avoids death cannot be the one who saves by dying. The condition they set for belief is precisely what faith does not require and what would make faith impossible.</p>',
    "31": '<p>"He saved others but he can\'t save himself!" — "saved others" (<em>allous esōsen</em>) — the chief priests and scribes acknowledge what they have witnessed without recognizing its significance. "He cannot save himself" (<em>heauton ou dynatai sōsai</em>) — in the irony of the Passion, this statement is true in a way the speakers do not intend: the logic of substitutionary salvation is that the one who saves others by bearing what they should bear cannot simultaneously spare himself. The mockery is theologically precise: self-rescue and saving others are incompatible in the mode of salvation Jesus is accomplishing.</p>',
    "32": '<p>"Let this Messiah, this king of Israel, come down now from the cross, that we may see and believe" — the demand for a sign before belief echoes the Pharisees\' demand in 8:11-12 (refused absolutely: "no sign will be given to this generation"). Now the chief priests set the same condition: a public vindication miracle. The condition is self-defeating: a Messiah who avoids the cross by miraculous self-rescue is not the Messiah who "must" suffer and be killed (8:31); the "must" (<em>dei</em>) of divine necessity cannot be negotiated away by the demand for an exempting miracle. The two rebels crucified with him "also heaped insults on him" — Luke 23:39-43 distinguishes between them, noting one repented.</p>',
    "33": '<p>Darkness from the sixth hour to the ninth hour (noon to 3 PM) — three hours of midday darkness. In the ancient world, unexpected darkness at noon was a recognized portent of divine displeasure or cosmic significance. Amos 8:9 (LXX) prophecied: "In that day, declares the Lord GOD, I will make the sun go down at noon and darken the earth in broad daylight. I will turn your religious festivals into mourning." Whether a solar eclipse, hamsin wind, or something else, the sign would have carried eschatological weight to first-century Jewish observers. The three-hour structure (3rd hour: crucifixion; 6th hour: darkness; 9th hour: death) may also reflect a liturgical time-marking pattern in the early church.</p>',
    "34": '<p>"Eloi, Eloi, lema sabachthani?" is a mixed Aramaic/Hebrew form of Psalm 22:1 (the Aramaic "Eloi" for "my God," the Hebrew "sabachthani" for "forsaken me"). Mark preserves the Aramaic words verbatim — consistent with the Petrine eyewitness tradition. The Aramaic "Eloi" sounds sufficiently like the Hebrew "Ēliyahu" (Elijah) that Aramaic-unfamiliar bystanders (Roman soldiers, Diaspora visitors) could plausibly mishear it (v.35). Psalm 22 begins in dereliction ("My God, my God, why have you forsaken me?") but ends in vindication (vv.22-31: "They will proclaim his righteousness, declaring to a people yet unborn: He has done it!"). Jesus\'s citation activates the whole Psalm, including its movement from abandonment to confident proclamation of God\'s deliverance.</p>',
    "35": '<p>"Listen, he\'s calling Elijah" — the confusion between "Eloi" (Aramaic: my God) and "Elijah" (Hebrew: Ēliyahu, "my God is Yahweh") is phonetically plausible for those unfamiliar with Aramaic. Elijah, who was translated directly to heaven without dying (2 Kgs 2:11), was expected in Jewish tradition to return before the Day of the LORD (Mal 4:5) and was associated with miraculous rescues and interventions. The bystanders\' interpretation — Elijah has been summoned and might come to rescue him — reflects the same category of Messianic rescue that the rulers and rebels demanded. The misunderstanding compounds the irony: the real Elijah (John the Baptist, 9:13) already came and was killed.</p>',
    "36": '<p>The wine vinegar on a sponge mounted on a staff echoes Psalm 69:21 ("They put gall in my food and gave me vinegar for my thirst"). Wine vinegar (<em>oxos</em>) was the standard drink of Roman soldiers — cheap, acidic, carried in canteens. It was not torture but a practical provision. The gesture may have been intended to revive Jesus enough to prolong his life and see if Elijah would come, as the speaker says: "Now leave him alone. Let\'s see if Elijah comes to take him down." The response mixes curiosity, mockery, and — perhaps from some — a genuine wondering whether something miraculous was about to happen.</p>',
    "37": '<p>"With a loud cry, Jesus breathed his last" (<em>apheis phōnēn megalēn exepneusen</em>) — the loud cry before death is unusual; crucifixion victims typically died by gradual asphyxiation and exhaustion, losing the ability to speak near the end. A loud cry at death would have been remarkable to observers — it suggests vitality remaining when physical weakness should have silenced him. Mark does not record the content of the final cry (Luke 23:46 identifies it as "Father, into your hands I commit my spirit"; John 19:30 as "It is finished"). The Petrine/Markan account preserves the raw fact of the cry without interpretation.</p>',
    "38": '<p>The temple curtain (<em>katapetasma</em>) torn in two "from top to bottom" — two curtains hung in the temple: the outer one (between the Court of Israel and the Court of Priests) and the inner one separating the Holy Place from the Holy of Holies. The inner veil is the one most commentators understand here, based on the theological significance: the Holy of Holies was God\'s dwelling, accessible only to the High Priest once a year on Yom Kippur. Josephus describes the inner veil as a Babylonian tapestry of enormous size (approximately 27 meters tall, 8 wide). "From top to bottom" specifies the direction as divine action (from above, not human tearing from below), and the tearing signals the end of the mediated, restricted access to God that the curtain represented.</p>',
    "39": '<p>The centurion stood "<em>ex enantias autou</em>" — directly opposite, facing him, observing how he died. A centurion commanded approximately 80 men; this one was the officer in charge of the execution. "Surely this man was the Son of God!" (<em>Alēthōs houtos ho anthrōpos huios theou ēn</em>) — "Son of God" in Roman culture was a standard title for emperors: Augustus was <em>Divi filius</em> (son of the divine Julius Caesar), and later emperors were acclaimed <em>Divi filius</em> or <em>filius dei</em>. The centurion may be using the phrase in a Roman register (a god-like, superhuman man) or in a Christian theological sense — Mark\'s narrative leaves the ambiguity unresolved. Structurally, his confession mirrors God\'s own declarations at the baptism (1:11) and transfiguration (9:7). The centurion, a Gentile Roman soldier, is the first human in the Gospel to call Jesus "Son of God."</p>',
    "40": '<p>Mary Magdalene, Mary the mother of James the younger and of Joseph, and Salome — the women watching from a distance (<em>apo makrothen</em>) are the consistent witnesses across the crucifixion, the burial (15:47), and the empty tomb (16:1). Mary Magdalene appears in all four Gospels\' resurrection accounts — she is the primary witness. "James the younger" (<em>ho mikros</em> — the small/lesser) distinguishes this James from James the son of Zebedee. The women\'s presence "from a distance" fulfills Psalm 38:11 ("My friends and companions avoid me because of my wounds; my neighbors stay far away") and Psalm 88:8.</p>',
    "41": '<p>"In Galilee these women had followed him and cared for his needs" — the women\'s discipleship is described with the same vocabulary as the male disciples\' (<em>ēkolouthoun</em>, followed; <em>diēkonoun</em>, served/ministered — the same root as <em>diakonos</em>, deacon/minister). They had been disciples since Galilee. "Many other women who had come up with him to Jerusalem were also there" — the female disciple group was substantial, extending beyond the three named. Their presence at the cross is historically and theologically significant: they are the witnesses who can testify to both the death and the burial (v.47) and thus validate the resurrection accounts (16:1-8).</p>',
    "42": '<p>Preparation Day (<em>paraskeye</em> — Greek for "preparation") was Friday, the day before the Sabbath (Saturday). The Sabbath began at sunset on Friday, and burial had to be completed before then under Jewish law (Deut 21:22-23 required burial before nightfall; not leaving a body exposed through the Sabbath was especially urgent). "As evening approached" — the urgency is temporal: sunset and the Sabbath were approaching, leaving only hours for burial arrangements. Joseph acts boldly and quickly because the window for legal burial is closing.</p>',
    "43": '<p>Joseph of Arimathea — Arimathea is usually identified with Ramathaim-Zophim (1 Sam 1:1), Samuel\'s hometown, about 30 km northwest of Jerusalem. As "a prominent member of the Council" (<em>euschēmōn bouleutēs</em>), he was a member of the Sanhedrin — the same body that had condemned Jesus. Luke 23:51 clarifies that he had not consented to the council\'s decision. "Waiting for the kingdom of God" — the Markan characterization places him among those who shared Jesus\'s eschatological hope without being an explicit disciple. Going boldly to Pilate to request the body of a crucified political criminal required genuine courage: association with an executed rebel could attract dangerous scrutiny.</p>',
    "44": '<p>Pilate was surprised (<em>ethaumasen</em>) that Jesus was already dead — crucifixion typically took one to three days; death in six hours was unusually swift and required verification before releasing the body. Roman law was explicit: the body could not be handed over without confirmation of death (to prevent revivification claims). The centurion\'s confirmation (v.45) provides the authoritative military attestation. Pilate\'s question and the centurion\'s answer serve a historical-apologetic function: they establish the official Roman confirmation of death, closing off the later suggestion (appearing in Jewish polemical sources) that Jesus had merely fainted.</p>',
    "45": '<p>The centurion confirms death; Pilate gives the body (<em>ptōma</em> — corpse) to Joseph. This transaction follows Roman law: the bodies of crucified criminals could be released to relatives or friends for burial; they were not always left on the cross to decompose (the standard Roman practice) when local sensitivities argued otherwise. Pilate\'s release of the body to a non-family-member (Joseph is not identified as a relative of Jesus) reflects the practical Roman accommodation of Jewish burial customs during a major festival — releasing the body prevents a potential public disturbance over improper Passover-week burial of a Jewish man.</p>',
    "46": '<p>Rock-cut tombs (<em>mnēmeion lelatomēmenon ek petras</em>) were the standard Jewish burial practice for families of means in the Second Temple period. The body was laid in a niche (<em>kokh</em>) cut into the rock wall; later the bones would be gathered into a limestone box (<em>ossuary</em>) for secondary burial. The rolling stone (<em>lithos</em>) — a large disc-shaped stone rolled in a carved channel across the entrance — was common for family tomb closures and provided security against grave robbery. Linen cloth (<em>sindōn</em>) was standard burial wrapping. The entire burial is conducted in legal and customary Jewish form, validating the burial\'s reality for the resurrection accounts that follow.</p>',
    "47": '<p>Mary Magdalene and Mary the mother of Joseph "saw where he was laid" — the same women who witnessed the crucifixion (v.40) now witness the burial, creating a chain of testimony: they can confirm death (crucifixion), confirm the burial location (so they can find it again), and will confirm the empty tomb (16:1-8). This chain of witness is historically careful: the women\'s testimony, though legally subordinate to male testimony in Jewish courts (<em>m. Shevuot</em> 4.1), provides continuous personal observation across the three events (death, burial, empty tomb). Their presence is the narrative foundation for the resurrection accounts that follow.</p>'
  },
  "16": {
    "2": '<p>"Very early on the first day of the week, just after sunrise" — "first day of the week" (<em>mia tōn sabbatōn</em>) is the Jewish designation for Sunday (the day after the Sabbath). The early church adopted this day as the Lord\'s Day (<em>kyriakē hēmera</em>, Rev 1:10; Didache 14.1: "On the Lord\'s Day, gather together") because of the resurrection, eventually distinguishing it from Sabbath observance. The specific detail "just after sunrise" (<em>anateilan­tos tou hēliou</em>) combines urgency (they came as early as they could) with a subtle contrast to the darkness at Jesus\'s death (15:33): the resurrection is associated with the return of light.</p>',
    "3": '<p>"Who will roll the stone away from the entrance of the tomb?" — the practical concern about the stone reflects the reality of the burial Joseph had arranged (15:46): the rolling stone was a substantial disc, requiring several people to move. The women\'s question as they walk shows that they went to the tomb expecting to anoint a body behind a sealed entrance, without any expectation of resurrection. Their concern about access is the concern of those who believe the story ends with burial. The question they ask on the way is answered immediately when they arrive — the stone is already moved.</p>',
    "4": '<p>"They saw that the stone, which was very large, had been rolled away" — the stone had been moved before their arrival; Mark does not explain by whom or how (contrast Matt 28:2, which describes an angel rolling it away at the moment of resurrection). The stone was "very large" (<em>sphodra megas</em>) — Mark emphasizes its size, underscoring that moving it required significant force. The passive voice ("had been rolled away") attributes the action to divine agency without specifying it. The women find not the closed tomb they expected but an opened one — the first sign that something other than ordinary burial has occurred.</p>',
    "5": '<p>"A young man dressed in a white robe sitting on the right side" — Mark does not use the word "angel" (<em>angelos</em>) here; the young man (<em>neaniskos</em>) in white is identified as angelic by context. White garments in Jewish apocalyptic literature consistently identified angelic or heavenly beings (Dan 7:9; 10:5; 2 Macc 11:8; 1 Enoch 71:1). The right side was the position of honor and authority. "They were alarmed" (<em>exethambēthēsan</em> — a strong compound: deeply startled, struck with astonishment) — the same root appears at 9:15 and 14:33; it is a response appropriate to an encounter with the numinous.</p>',
    "6": '<p>"Don\'t be alarmed. You are looking for Jesus the Nazarene, who was crucified. He has risen! He is not here. See the place where they laid him." — the angel\'s proclamation is the first Easter announcement in the Gospel tradition. Four elements: a command to stop being afraid (conventional angelic formula: cf. Dan 10:12; Luke 1:13,30; 2:10), identification of the one they seek (Jesus of Nazareth, the crucified one — the identification is historically specific: not a vision or a spirit but the same person who was crucified), the proclamation of resurrection ("he has risen," <em>ēgerthē</em> — divine passive: God raised him), and an invitation to see the empty tomb as evidence. The proclamation grounds the resurrection claim in historical specificity.</p>',
    "7": '<p>"But go, tell his disciples and Peter" — Peter\'s specific naming after his three-fold denial (14:66-72) is the resurrection\'s first act of restoration. The angel singles out Peter by name — he is not excluded from the community despite his failure; he is specifically summoned. The rendezvous instruction ("He is going ahead of you into Galilee. There you will see him, just as he told you") fulfills 14:28 ("after I have risen, I will go ahead of you into Galilee"). The return to Galilee is not retreat but recommissioning: the ministry that began in Galilee (1:14) will be reconstituted there. Paul\'s tradition (1 Cor 15:5) confirms that Peter was among the first resurrection witnesses.</p>',
    "8": '<p>"Trembling and bewildered, the women went out and fled from the tomb. They said nothing to anyone, because they were afraid" (<em>ephobounto gar</em> — "for they were afraid") — the original ending of Mark. This ending is attested by Codex Sinaiticus, Codex Vaticanus, and most early witnesses; Eusebius and Jerome note that almost all Greek copies they knew ended here. The abruptness puzzled ancient readers (which is why vv.9-20 were added), but it is consistent with Mark\'s literary style and theology. The women\'s silence and fear are not a final statement of failure but a literary technique: the reader now holds the news the women could not speak; the Gospel ends with an invitation — the story does not end here; it continues with the reader who has received the proclamation the women could not yet speak.</p>',
    "9": '<p>Mark 16:9-20, the "Long Ending," is absent from Codex Sinaiticus (א) and Codex Vaticanus (B), the oldest substantially complete Greek manuscripts of the NT, as well as from Clement of Alexandria, Origen, Eusebius, and Jerome\'s testimony about the manuscripts they consulted. The Long Ending is present in the Western text (D) and the Byzantine majority text, but its textual history indicates it was added in the second century to provide a more satisfying conclusion. The material in vv.9-20 is not invented — it represents authentic early traditions about Jesus\'s resurrection appearances (Mary Magdalene\'s encounter, the Emmaus disciples, the commissioning, the ascension) — but the question is whether it was part of Mark\'s original Gospel.</p>',
    "10": '<p>Mary Magdalene goes and tells those who had been with Jesus — "mourning and weeping" (<em>penthousin kai klaiousin</em>). The grief described is consistent with the disciples\' post-crucifixion state: they have witnessed (or heard of) the death of the one they believed would redeem Israel (Luke 24:21). Mary\'s report is the first resurrection testimony in the Long Ending\'s sequence. The pattern of announcement, disbelief, and subsequent appearance (vv.10-14) mirrors the pattern in Luke 24 and John 20, suggesting the Long Ending is drawing on the other Gospel traditions.</p>',
    "11": '<p>"When they heard that Jesus was alive and that she had seen him, they did not believe it" (<em>ēpistēsan</em>) — the disciples\' initial disbelief of Mary Magdalene\'s testimony is consistent across all four Gospel resurrection accounts (Luke 24:11: "But they did not believe the women, because their words seemed to them like nonsense"). In Jewish law, women\'s testimony was legally inferior to men\'s in many contexts (m. Shevuot 4.1). The disciples\' disbelief is also psychologically realistic: the crucifixion had comprehensively destroyed their expectation, and resurrection from the dead was outside their framework of expectation even after Jesus\'s predictions.</p>',
    "12": '<p>"Afterward Jesus appeared in a different form to two of them while they were walking in the country" — this corresponds to the Emmaus road appearance of Luke 24:13-35, where two disciples traveling to Emmaus encounter the risen Jesus but do not initially recognize him ("their eyes were prevented from recognizing him," Luke 24:16). "In a different form" (<em>en heterai morphē</em>) is the Long Ending\'s compact summary of what Luke narrates at length: the risen Jesus is not always immediately recognizable in his resurrection appearances, a consistent feature of the appearance accounts (cf. John 20:14-15, Mary Magdalene does not recognize him; John 21:4, the disciples do not recognize him).</p>',
    "13": '<p>"These returned and reported it to the rest; but they did not believe them either" — the continuing disbelief accumulates through three failed testimony sequences: Mary Magdalene (v.11), the two Emmaus travelers (v.13), and finally the appearance to the Eleven themselves (v.14) ends the chain. The pattern of repeated disbelief before the final confronting appearance serves a historical apologetic purpose: the resurrection faith did not arise from credulity or wishful thinking but from appearances that overcame systematic disbelief among the very people who would have most wanted to believe but could not.</p>',
    "14": '<p>"Later Jesus appeared to the Eleven as they were eating; he rebuked them for their lack of faith and their stubborn refusal to believe those who had seen him after he had risen" — the appearance to the Eleven corresponds to Luke 24:36-43 and John 20:19-23. The rebuke for "stubborn refusal to believe" (<em>sklērokardia</em>, hardness of heart — the same term Jesus used to rebuke the disciples\' failure to understand the feedings, 8:17) establishes that the resurrection witnesses were not naive believers but resistant skeptics who required confrontation with the physical reality of the risen Christ before they would believe.</p>',
    "15": '<p>"Go into all the world and preach the gospel to all creation" — the Great Commission of the Long Ending (corresponding to Matt 28:19-20, Luke 24:46-49, John 20:21-23, Acts 1:8). "All creation" (<em>pasē tē ktisei</em>) is broader than Matthew\'s "all nations" — it includes the entire created order as the scope of the gospel\'s reach. The commission\'s context in Gentile-oriented Mark makes the "all the world" language particularly resonant: the Gentile Roman audience for whom Mark was written is included in the "all creation" that the gospel addresses.</p>',
    "16": '<p>"Whoever believes and is baptized will be saved, but whoever does not believe will be condemned" — the connection of belief with baptism reflects early Christian practice (Acts 2:38, 8:12-13, 16:31-33) where baptism was the immediate public expression of belief and the act of incorporation into the community. The negative statement concerns only unbelief ("whoever does not believe") — not absence of baptism. The verse is not establishing baptism as independently necessary for salvation but as the expected outward expression of the belief that saves; the condemnation comes from unbelief, not from unbaptized status.</p>',
    "17": '<p>"And these signs will accompany those who believe: In my name they will drive out demons; they will speak in new tongues" — the promised signs correspond to documented practices in the early church: exorcism is a consistent feature of Acts (5:16, 8:7, 16:18, 19:12) and Paul\'s letters (1 Cor 12:10 lists "distinguishing between spirits"); speaking in new tongues (<em>glōssais lalēsousin kainais</em>) appears at Pentecost (Acts 2:4), Caesarea (Acts 10:46), Ephesus (Acts 19:6), and is discussed at length in 1 Corinthians 12-14. These promises in the Long Ending reflect the actual experience of the early Gentile mission.</p>',
    "18": '<p>"They will pick up snakes with their hands; and when they drink deadly poison, it will not hurt them at all; they will place their hands on sick people, and they will get well" — the snake-handling promise echoes Luke 10:19 ("I have given you authority to tread on snakes and scorpions") and is illustrated accidentally in Acts 28:3-6 (Paul is bitten by a viper on Malta but experiences no harm). The healing of the sick by hand-laying is consistent with the practice throughout Acts (3:7, 9:17, 28:8). The poison immunity is not otherwise illustrated in the NT but appears in early Christian tradition (Eusebius HE 3.39.9 reports a similar claim about the Apostle John).</p>',
    "19": '<p>"After the Lord Jesus had spoken to them, he was taken up into heaven and he sat at the right hand of God" — the Ascension is narrated in Luke 24:50-51 and Acts 1:9-11. "Sat at the right hand of God" is the language of Psalm 110:1 ("The LORD says to my lord: \'Sit at my right hand until I make your enemies a footstool for your feet\'") — the Psalm Jesus quoted at his trial (14:62: "you will see the Son of Man sitting at the right hand of the Mighty One"). The Ascension and session at the right hand is the fulfillment of the Danielic promise (Dan 7:13-14) that Jesus claimed before the Sanhedrin: the vindicated Son of Man enthroned in the presence of the Ancient of Days.</p>',
    "20": '<p>"Then the disciples went out and preached everywhere, and the Lord worked with them and confirmed his word by the signs that accompanied it" — the Long Ending closes with a summary that corresponds to the book of Acts as a whole: the disciples\' mission to "everywhere" (Acts 1-28 traces this from Jerusalem to Rome), and the Lord\'s confirming presence through signs (Acts 2:43, 3:1-10, 5:12-16, 8:6-7, 14:3). The Long Ending does not end the Gospel with an ending but with a beginning: the mission that Mark\'s Gospel narrates (1:1: "the beginning of the good news of Jesus Christ") continues in the preaching of those who witnessed the resurrection and received the commission to take the gospel to all creation.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', 'mark')
    merge_comm(existing, MARK)
    save_comm('mkt-context', 'mark', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Mark mkt-context chs 15-16: {total} verses total written.')

if __name__ == '__main__':
    main()
